const std = @import("std"); const runtime = @import("runtime"); const input_mod = @import("input");
test "keys paste preedit commit mouse and late callbacks use production runtime" { var rt = try runtime.TerminalRuntime.init(std.testing.allocator, "cat", 80, 24); var input = input_mod.Input.init(&rt); defer input.deinit(); try input.setPreedit("compose"); try std.testing.expectEqualStrings("compose", input.preedit.items); try input.commit("committed"); try std.testing.expectError(error.UnsafePaste, input.paste("danger\n", false)); const mouse = input.pointer(9999, 9999, 80, 24, 1, true); try std.testing.expectEqual(@as(u16, 79), mouse.column); rt.close(); try std.testing.expectError(error.StaleCallback, input.key(.enter)); }
